    public void handleOrderBookSnapshot(Client client, Object message, Object subscription)
    {
        //
        //     {
        //         "id": 1583473663565,
        //         "rep": "market.btcusdt.mbp.150",
        //         "status": "ok",
        //         "ts": 1698359289261,
        //         "data": {
        //             "seqNum": 104999417756,
        //             "bids": [
        //                 [9058.27, 0],
        //                 [9058.43, 0],
        //                 [9058.99, 0],
        //             ],
        //             "asks": [
        //                 [9084.27, 0.2],
        //                 [9085.69, 0],
        //                 [9085.81, 0],
        //             ]
        //         }
        //     }
        //
        Object symbol = this.safeString(subscription, "symbol");
        Object messageHash = this.safeString(subscription, "messageHash");
        Object id = this.safeString(message, "id");
        Object lastTimestamp = this.safeInteger(subscription, "lastTimestamp");
        try
        {
            Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
            Object data = this.safeValue(message, "data");
            Object messages = ((java.util.List<Object>)Helpers.GetValue(orderbook, "cache"));
            Object firstMessage = this.safeValue(messages, 0, new java.util.HashMap<String, Object>() {{}});
            Object snapshot = this.parseOrderBook(data, symbol);
            Object tick = this.safeValue(firstMessage, "tick");
            Object sequence = this.safeInteger(tick, "prevSeqNum");
            Object nonce = this.safeInteger(data, "seqNum");
            Helpers.addElementToObject(snapshot, "nonce", nonce);
            Object snapshotTimestamp = this.safeInteger(message, "ts");
            Helpers.addElementToObject(subscription, "lastTimestamp", snapshotTimestamp);
            Object snapshotLimit = this.safeInteger(subscription, "limit");
            Object snapshotOrderBook = this.orderBook(snapshot, snapshotLimit);
            client.resolve(snapshotOrderBook, id);
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(sequence, null))) || Helpers.isTrue((Helpers.isLessThan(nonce, sequence)))))
            {
                Object maxAttempts = this.handleOption("watchOrderBook", "maxRetries", 3);
                Object numAttempts = this.safeInteger(subscription, "numAttempts", 0);
                // retry to synchronize if we have not reached maxAttempts yet
                if (Helpers.isTrue(Helpers.isLessThan(numAttempts, maxAttempts)))
                {
                    // safety guard
                    if (Helpers.isTrue(Helpers.inOp(client.subscriptions, messageHash)))
                    {
                        numAttempts = this.sum(numAttempts, 1);
                        Object delayTime = this.sum(1000, Helpers.subtract(lastTimestamp, snapshotTimestamp));
                        Helpers.addElementToObject(subscription, "numAttempts", numAttempts);
                        Helpers.addElementToObject(client.subscriptions, messageHash, subscription);
                        this.scheduleCallback(delayTime, "watchOrderBookSnapshot", client, message, subscription);
                    }
                } else
                {
                    throw new InvalidNonce((String)Helpers.add(Helpers.add(Helpers.add(Helpers.add(Helpers.add(this.id, " failed to synchronize WebSocket feed with the snapshot for symbol "), symbol), " in "), String.valueOf(maxAttempts)), " attempts")) ;
                }
            } else
            {
                Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
                // unroll the accumulated deltas
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(messages)); i++)
                {
                    this.handleOrderBookMessage(client, Helpers.GetValue(messages, i));
                }
                Helpers.addElementToObject(orderbook, "cache", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Helpers.addElementToObject(this.orderbooks, symbol, orderbook);
                client.resolve(orderbook, messageHash);
            }
        } catch(Exception e)
        {
            ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
            ((java.util.Map<String,Object>)this.orderbooks).remove((String)symbol);
            client.reject(e, messageHash);
        }
    }

    public java.util.concurrent.CompletableFuture<Object> watchOrderBookSnapshot(Client client, Object message, Object subscription)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object messageHash = this.safeString(subscription, "messageHash");
            Object symbol = this.safeString(subscription, "symbol");
            Object limit = this.safeInteger(subscription, "limit");
            Object timestamp = this.safeInteger(message, "ts");
            Object parameters = this.safeValue(subscription, "params");
            Object attempts = this.safeInteger(subscription, "numAttempts", 0);
            Object market = this.market(symbol);
            Object url = this.getUrlByMarketType(Helpers.GetValue(market, "type"), Helpers.GetValue(market, "linear"), false, true);
            Object requestId = this.requestId();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "req", messageHash );
                put( "id", requestId );
            }};
            // this is a temporary subscription by a specific requestId
            // it has a very short lifetime until the snapshot is received over ws
            Object snapshotSubscription = new java.util.HashMap<String, Object>() {{
                put( "id", requestId );
                put( "messageHash", messageHash );
                put( "symbol", symbol );
                put( "limit", limit );
                put( "params", parameters );
                put( "numAttempts", attempts );
                put( "lastTimestamp", timestamp );
                put( "method", "handleOrderBookSnapshot");
            }};
            try
            {
                Object orderbook = (this.watch(url, requestId, request, requestId, snapshotSubscription)).join();
                return Helpers.callDynamically(orderbook, "limit", new Object[]{});
            } catch(Exception e)
            {
                ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
                client.reject(e, messageHash);
            }
            return null;
        });

    }

    public void handleDelta(Object bookside, Object delta)
    {
        Object price = this.safeFloat(delta, 0);
        Object amount = this.safeFloat(delta, 1);
        Helpers.callDynamically(bookside, "store", new Object[]{price, amount});
    }

    public void handleDeltas(Object bookside, Object deltas)
    {
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(deltas)); i++)
        {
            this.handleDelta(bookside, Helpers.GetValue(deltas, i));
        }
    }

    public void handleOrderBookMessage(Client client, Object message)
    {
        // spot markets
        //
        //     {
        //         "ch": "market.btcusdt.mbp.150",
        //         "ts": 1583472025885,
        //         "tick": {
        //             "seqNum": 104998984994,
        //             "prevSeqNum": 104998984977,
        //             "bids": [
        //                 [9058.27, 0],
        //                 [9058.43, 0],
        //                 [9058.99, 0],
        //             ],
        //             "asks": [
        //                 [9084.27, 0.2],
        //                 [9085.69, 0],
        //                 [9085.81, 0],
        //             ]
        //         }
        //     }
        //
        // non-spot market update
        //
        //     {
        //         "ch":"market.BTC220218.depth.size_150.high_freq",
        //         "tick":{
        //             "asks":[],
        //             "bids":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "ch":"market.BTC220218.depth.size_150.high_freq",
        //             "event":"update",
        //             "id":152727500274,
        //             "mrid":152727500274,
        //             "ts":1645023376098,
        //             "version":37536690
        //         },
        //         "ts":1645023376098
        //     }
        // non-spot market snapshot
        //
        //     {
        //         "ch":"market.BTC220218.depth.size_150.high_freq",
        //         "tick":{
        //             "asks":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "bids":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "ch":"market.BTC220218.depth.size_150.high_freq",
        //             "event":"snapshot",
        //             "id":152727500274,
        //             "mrid":152727500274,
        //             "ts":1645023376098,
        //             "version":37536690
        //         },
        //         "ts":1645023376098
        //     }
        //
        Object ch = this.safeValue(message, "ch");
        Object parts = Helpers.split(ch, ".");
        Object marketId = this.safeString(parts, 1);
        Object market = this.safeMarket(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        Object tick = this.safeValue(message, "tick", new java.util.HashMap<String, Object>() {{}});
        Object seqNum = this.safeInteger(tick, "seqNum");
        Object prevSeqNum = this.safeInteger(tick, "prevSeqNum");
        Object eventVar = this.safeString(tick, "event");
        Object version = this.safeInteger(tick, "version");
        Object timestamp = this.safeInteger(message, "ts");
        if (Helpers.isTrue(Helpers.isEqual(eventVar, "snapshot")))
        {
            Object snapshot = this.parseOrderBook(tick, symbol, timestamp);
            Helpers.callDynamically(orderbook, "reset", new Object[]{snapshot});
            Helpers.addElementToObject(orderbook, "nonce", version);
        }
        if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(prevSeqNum, null))) && Helpers.isTrue(Helpers.isGreaterThan(prevSeqNum, this.safeInteger(orderbook, "nonce", 0)))))
        {
            Object checksum = this.handleOption("watchOrderBook", "checksum", true);
            if (Helpers.isTrue(checksum))
            {
                throw new ChecksumError((String)Helpers.add(Helpers.add(this.id, " "), this.orderbookChecksumMessage(symbol))) ;
            }
        }
        Object spotConditon = Helpers.isTrue(Helpers.GetValue(market, "spot")) && Helpers.isTrue((Helpers.isEqual(prevSeqNum, Helpers.GetValue(orderbook, "nonce"))));
        Object nonSpotCondition = Helpers.isTrue(Helpers.GetValue(market, "contract")) && Helpers.isTrue((Helpers.isEqual(Helpers.subtract(version, 1), Helpers.GetValue(orderbook, "nonce"))));
        if (Helpers.isTrue(Helpers.isTrue(spotConditon) || Helpers.isTrue(nonSpotCondition)))
        {
            Object asks = this.safeValue(tick, "asks", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object bids = this.safeValue(tick, "bids", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            this.handleDeltas(Helpers.GetValue(orderbook, "asks"), asks);
            this.handleDeltas(Helpers.GetValue(orderbook, "bids"), bids);
            Helpers.addElementToObject(orderbook, "nonce", ((Helpers.isTrue(spotConditon))) ? seqNum : version);
            Helpers.addElementToObject(orderbook, "timestamp", timestamp);
            Helpers.addElementToObject(orderbook, "datetime", this.iso8601(timestamp));
        }
    }

    public void handleOrderBook(Client client, Object message)
    {
        //
        // deltas
        //
        // spot markets
        //
        //     {
        //         "ch": "market.btcusdt.mbp.150",
        //         "ts": 1583472025885,
        //         "tick": {
        //             "seqNum": 104998984994,
        //             "prevSeqNum": 104998984977,
        //             "bids": [
        //                 [9058.27, 0],
        //                 [9058.43, 0],
        //                 [9058.99, 0],
        //             ],
        //             "asks": [
        //                 [9084.27, 0.2],
        //                 [9085.69, 0],
        //                 [9085.81, 0],
        //             ]
        //         }
        //     }
        //
        // non spot markets
        //
        //     {
        //         "ch":"market.BTC220218.depth.size_150.high_freq",
        //         "tick":{
        //             "asks":[],
        //             "bids":[
        //                 [43445.74,1],
        //                 [43444.48,0 ],
        //                 [40593.92,9]
        //             ],
        //             "ch":"market.BTC220218.depth.size_150.high_freq",
        //             "event":"update",
        //             "id":152727500274,
        //             "mrid":152727500274,
        //             "ts":1645023376098,
        //             "version":37536690
        //         },
        //         "ts":1645023376098
        //     }
        //
        Object messageHash = this.safeString(message, "ch");
        Object tick = this.safeDict(message, "tick");
        Object eventVar = this.safeString(tick, "event");
        Object ch = this.safeString(message, "ch");
        Object parts = Helpers.split(ch, ".");
        Object marketId = this.safeString(parts, 1);
        Object symbol = this.safeSymbol(marketId);
        if (!Helpers.isTrue((Helpers.inOp(this.orderbooks, symbol))))
        {
            Object size = this.safeString(parts, 3);
            Object sizeParts = Helpers.split(size, "_");
            Object limit = this.safeInteger(sizeParts, 1);
            Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit));
        }
        Object orderbook = Helpers.GetValue(this.orderbooks, symbol);
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(eventVar, null))) && Helpers.isTrue((Helpers.isEqual(Helpers.GetValue(orderbook, "nonce"), null)))))
        {
            ((java.util.List<Object>)((java.util.List<Object>)Helpers.GetValue(orderbook, "cache"))).add(message);
        } else
        {
            this.handleOrderBookMessage(client, message);
            client.resolve(orderbook, messageHash);
        }
    }

    public void handleOrderBookSubscription(Client client, Object message, Object subscription)
    {
        Object symbol = this.safeString(subscription, "symbol");
        Object market = this.market(symbol);
        Object limit = this.safeInteger(subscription, "limit");
        Helpers.addElementToObject(this.orderbooks, symbol, this.orderBook(new java.util.HashMap<String, Object>() {{}}, limit));
        if (Helpers.isTrue(Helpers.GetValue(market, "spot")))
        {
            this.spawn(() -> { try { this.watchOrderBookSnapshot(client, message, subscription); } catch(Exception _e) { throw new RuntimeException(_e); } });
        }
    }

    /**
     * @method
     * @name htx#watchMyTrades
     * @description watches information on multiple trades made by the user
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=7ec53dd5-7773-11ed-9966-0242ac110003
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=8cb89359-77b5-11ed-9966-195a35275ff
     * @param {string} symbol unified market symbol of the market trades were made in
     * @param {int} [since] the earliest time in ms to fetch trades for
     * @param {int} [limit] the maximum number of trade structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=trade-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchMyTrades(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            this.checkRequiredCredentials();
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object type = null;
            Object marketId = "*"; // wildcard
            Object market = null;
            Object messageHash = null;
            Object channel = null;
            Object trades = null;
            Object subType = null;
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                type = Helpers.GetValue(market, "type");
                subType = ((Helpers.isTrue(Helpers.GetValue(market, "linear")))) ? "linear" : "inverse";
                marketId = Helpers.GetValue(market, "lowercaseId");
            } else
            {
                type = this.safeString(this.options, "defaultType", "spot");
                type = this.safeString(parameters, "type", type);
                subType = this.safeString2(this.options, "subType", "defaultSubType", "linear");
                subType = this.safeString(parameters, "subType", subType);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("type", "subType")));
            }
            Object linear = (Helpers.isEqual(subType, "linear"));
            Object swap = (Helpers.isEqual(type, "swap"));
            Object future = (Helpers.isEqual(type, "future"));
            Object isV5Linear = (Helpers.isTrue(linear) && Helpers.isTrue((Helpers.isTrue(swap) || Helpers.isTrue(future))));
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                Object mode = null;
                if (Helpers.isTrue(Helpers.isEqual(mode, null)))
                {
                    mode = this.safeString2(this.options, "watchMyTrades", "mode", "0");
                    mode = this.safeString(parameters, "mode", mode);
                    parameters = this.omit(parameters, "mode");
                }
                messageHash = Helpers.add(Helpers.add(Helpers.add(Helpers.add("trade.clearing", "#"), marketId), "#"), mode);
                channel = messageHash;
            } else if (Helpers.isTrue(isV5Linear))
            {
                Object channelAndMessageHashAndParams = this.getV5LinearChannelAndMessageHash("trade", market, parameters);
                channel = this.safeString(channelAndMessageHashAndParams, 0);
                messageHash = this.safeString(channelAndMessageHashAndParams, 1);
                parameters = this.safeValue(channelAndMessageHashAndParams, 2, new java.util.HashMap<String, Object>() {{}});
            } else
            {
                Object channelAndMessageHash = this.getOrderChannelAndMessageHash(type, subType, market, parameters);
                channel = this.safeString(channelAndMessageHash, 0);
                Object orderMessageHash = this.safeString(channelAndMessageHash, 1);
                // we will take advantage of the order messageHash because already handles stuff
                // like symbol/margin/subtype/type variations
                messageHash = Helpers.add(Helpers.add(orderMessageHash, ":"), "trade");
            }
            Object subscriptionParams = new java.util.HashMap<String, Object>() {{
                put( "isV5", isV5Linear );
            }};
            trades = (this.subscribePrivate(channel, messageHash, type, subType, parameters, subscriptionParams)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(trades, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(trades, symbol, since, limit, true);
        });

    }

    public Object getOrderChannelAndMessageHash(Object type, Object subType, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object messageHash = null;
        Object channel = null;
        Object orderType = this.safeString(this.options, "orderType", "orders"); // orders or matchOrders
        orderType = this.safeString(parameters, "orderType", orderType);
        parameters = this.omit(parameters, "orderType");
        Object marketCode = ((Helpers.isTrue((!Helpers.isEqual(market, null))))) ? ((String)Helpers.GetValue(market, "lowercaseId")).toLowerCase() : null;
        Object baseId = ((Helpers.isTrue((!Helpers.isEqual(market, null))))) ? Helpers.GetValue(market, "baseId") : null;
        Object prefix = orderType;
        messageHash = prefix;
        if (Helpers.isTrue(Helpers.isEqual(subType, "linear")))
        {
            // USDT Margined Contracts Example: LTC/USDT:USDT
            Object marginMode = this.safeString(parameters, "margin", "cross");
            Object marginPrefix = ((Helpers.isTrue((Helpers.isEqual(marginMode, "cross"))))) ? Helpers.add(prefix, "_cross") : prefix;
            messageHash = marginPrefix;
            if (Helpers.isTrue(!Helpers.isEqual(marketCode, null)))
            {
                messageHash = Helpers.add(messageHash, Helpers.add(".", marketCode));
                channel = messageHash;
            } else
            {
                channel = Helpers.add(Helpers.add(marginPrefix, "."), "*");
            }
        } else if (Helpers.isTrue(Helpers.isEqual(type, "future")))
        {
            // inverse futures Example: BCH/USD:BCH-220408
            if (Helpers.isTrue(!Helpers.isEqual(baseId, null)))
            {
                channel = Helpers.add(Helpers.add(prefix, "."), ((String)baseId).toLowerCase());
                messageHash = channel;
            } else
            {
                channel = Helpers.add(Helpers.add(prefix, "."), "*");
            }
        } else
        {
            // inverse swaps: Example: BTC/USD:BTC
            if (Helpers.isTrue(!Helpers.isEqual(marketCode, null)))
            {
                channel = Helpers.add(Helpers.add(prefix, "."), marketCode);
                messageHash = channel;
            } else
            {
                channel = Helpers.add(Helpers.add(prefix, "."), "*");
            }
        }
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(channel, messageHash));
    }

    public Object getV5LinearChannelAndMessageHash(Object topic, Object... optionalArgs)
    {
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
        Object contractCode = ((Helpers.isTrue((!Helpers.isEqual(market, null))))) ? Helpers.GetValue(market, "id") : this.safeString(parameters, "contract_code", "*");
        Object channel = topic;
        Object messageHash = ((Helpers.isTrue((Helpers.isEqual(contractCode, "*"))))) ? topic : (Helpers.add(Helpers.add(topic, "."), ((String)contractCode).toLowerCase()));
        parameters = this.omit(parameters, "contract_code");
        final Object finalContractCode = contractCode;
        Object requestParams = this.extend(new java.util.HashMap<String, Object>() {{
            put( "contract_code", finalContractCode );
        }}, parameters);
        return new java.util.ArrayList<Object>(java.util.Arrays.asList(channel, messageHash, requestParams));
    }

    /**
     * @method
     * @name htx#watchOrders
     * @description watches information on multiple orders made by the user
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=7ec53c8f-7773-11ed-9966-0242ac110003
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=8cb89359-77b5-11ed-9966-195a208afe7
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object type = null;
            Object subType = null;
            Object market = null;
            Object suffix = "*"; // wildcard
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                type = Helpers.GetValue(market, "type");
                suffix = Helpers.GetValue(market, "lowercaseId");
                subType = ((Helpers.isTrue(Helpers.GetValue(market, "linear")))) ? "linear" : "inverse";
            } else
            {
                type = this.safeString(this.options, "defaultType", "spot");
                type = this.safeString(parameters, "type", type);
                subType = this.safeString2(this.options, "subType", "defaultSubType", "linear");
                subType = this.safeString(parameters, "subType", subType);
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("type", "subType")));
            }
            Object linear = (Helpers.isEqual(subType, "linear"));
            Object swap = (Helpers.isEqual(type, "swap"));
            Object future = (Helpers.isEqual(type, "future"));
            Object isV5Linear = (Helpers.isTrue(linear) && Helpers.isTrue((Helpers.isTrue(swap) || Helpers.isTrue(future))));
            Object messageHash = null;
            Object channel = null;
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                messageHash = Helpers.add(Helpers.add("orders", "#"), suffix);
                channel = messageHash;
            } else if (Helpers.isTrue(isV5Linear))
            {
                Object channelAndMessageHashAndParams = this.getV5LinearChannelAndMessageHash("orders", market, parameters);
                channel = this.safeString(channelAndMessageHashAndParams, 0);
                messageHash = this.safeString(channelAndMessageHashAndParams, 1);
                parameters = this.safeValue(channelAndMessageHashAndParams, 2, new java.util.HashMap<String, Object>() {{}});
            } else
            {
                Object channelAndMessageHash = this.getOrderChannelAndMessageHash(type, subType, market, parameters);
                channel = this.safeString(channelAndMessageHash, 0);
                messageHash = this.safeString(channelAndMessageHash, 1);
            }
            Object subscriptionParams = new java.util.HashMap<String, Object>() {{
                put( "isV5", isV5Linear );
            }};
            Object orders = (this.subscribePrivate(channel, messageHash, type, subType, parameters, subscriptionParams)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(orders, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySinceLimit(orders, since, limit, "timestamp", true);
        });

    }

    public void handleOrder(Client client, Object message)
    {
        //
        // spot
        //
        //     for new order creation
        //
        //     {
        //         "action":"push",
        //         "ch":"orders#btcusdt", // or "orders#*" for global subscriptions
        //         "data": {
        //             "orderStatus": "submitted",
        //             "eventType": "creation",
        //             "totalTradeAmount": 0 // for "submitted" order status
        //             "orderCreateTime": 1645116048355, // only when `submitted` status
        //             "orderSource": "spot-web",
        //             "accountId": 44234548,
        //             "orderPrice": "100",
        //             "orderSize": "0.05",
        //             "symbol": "ethusdt",
        //             "type": "buy-limit",
        //             "orderId": "478861479986886",
        //             "clientOrderId": '',
        //         }
        //     }
        //
        //     for filled order, additional fields are present:
        //
        //             "orderStatus": "filled",
        //             "eventType": "trade",
        //             "totalTradeAmount": "5.9892649859",
        //             "tradePrice": "0.676669",
        //             "tradeVolume": "8.8511",
        //             "tradeTime": 1760427775894,
        //             "aggressor": false,
        //             "execAmt": "8.8511",
        //             "tradeId": 100599712781,
        //             "remainAmt": "0",
        //
        // spot wrapped trade
        //
        //     {
        //         "action": "push",
        //         "ch": "orders#ltcusdt",
        //         "data": {
        //             "tradePrice": "130.01",
        //             "tradeVolume": "0.0385",
        //             "tradeTime": 1648714741525,
        //             "aggressor": true,
        //             "execAmt": "0.0385",
        //             "orderSource": "spot-web",
        //             "orderSize": "0.0385",
        //             "remainAmt": "0",
        //             "tradeId": 101541578884,
        //             "symbol": "ltcusdt",
        //             "type": "sell-market",
        //             "eventType": "trade",
        //             "clientOrderId": '',
        //             "orderStatus": "filled",
        //             "orderId": 509835753860328
        //         }
        //     }
        //
        // non spot order
        //
        // {
        //     "contract_type": "swap",
        //     "pair": "LTC-USDT",
        //     "business_type": "swap",
        //     "op": "notify",
        //     "topic": "orders_cross.ltc-usdt",
        //     "ts": 1650354508696,
        //     "symbol": "LTC",
        //     "contract_code": "LTC-USDT",
        //     "volume": 1,
        //     "price": 110.34,
        //     "order_price_type": "lightning",
        //     "direction": "sell",
        //     "offset": "close",
        //     "status": 6,
        //     "lever_rate": 1,
        //     "order_id": "966002354015051776",
        //     "order_id_str": "966002354015051776",
        //     "client_order_id": null,
        //     "order_source": "web",
        //     "order_type": 1,
        //     "created_at": 1650354508649,
        //     "trade_volume": 1,
        //     "trade_turnover": 11.072,
        //     "fee": -0.005536,
        //     "trade_avg_price": 110.72,
        //     "margin_frozen": 0,
        //     "profit": -0.045,
        //     "trade": [
        //       {
        //         "trade_fee": -0.005536,
        //         "fee_asset": "USDT",
        //         "real_profit": 0.473,
        //         "profit": -0.045,
        //         "trade_id": 86678766507,
        //         "id": "86678766507-966002354015051776-1",
        //         "trade_volume": 1,
        //         "trade_price": 110.72,
        //         "trade_turnover": 11.072,
        //         "created_at": 1650354508656,
        //         "role": "taker"
        //       }
        //     ],
        //     "canceled_at": 0,
        //     "fee_asset": "USDT",
        //     "margin_asset": "USDT",
        //     "uid": "359305390",
        //     "liquidation_type": "0",
        //     "margin_mode": "cross",
        //     "margin_account": "USDT",
        //     "is_tpsl": 0,
        //     "real_profit": 0.473,
        //     "trade_partition": "USDT",
        //     "reduce_only": 1
        //   }
        //
        //
        // linear v5 watchOrders
        //
        //     {
        //         "op": "notify",
        //         "topic": "orders",
        //         "contract_code": "BTC-USDT",
        //         "ts": 1782367563267,
        //         "uid": "359305390",
        //         "data": {
        //             "side": "buy",
        //             "type": "limit",
        //             "price": "40000",
        //             "volume": "1",
        //             "state": "new",
        //             "profit": "0",
        //             "contract_code": "BTC-USDT",
        //             "position_side": "both",
        //             "price_match": null,
        //             "order_id": "1519705236917489664",
        //             "client_order_id": "1519705236917489664",
        //             "margin_mode": "cross",
        //             "lever_rate": 10,
        //             "order_source": "api",
        //             "reduce_only": false,
        //             "time_in_force": "gtc",
        //             "trade_avg_price": "0",
        //             "trade_volume": "0",
        //             "trade_turnover": "0",
        //             "fee_currency": null,
        //             "fee": "0",
        //             "tp_trigger_price": "",
        //             "tp_order_price": "",
        //             "tp_type": "",
        //             "tp_trigger_price_type": "",
        //             "sl_trigger_price": "",
        //             "sl_order_price": "",
        //             "sl_type": "",
        //             "sl_trigger_price_type": "",
        //             "contract_type": "swap",
        //             "cancel_reason": "",
        //             "created_time": "1782367563239",
        //             "updated_time": "1782367563239",
        //             "self_match_prevent": "cancel_taker",
        //             "amend_origin_volume": "",
        //             "amend_source": "",
        //             "amend_result": ""
        //         }
        //     }
        //
        Object messageHash = this.safeString2(message, "ch", "topic");
        Object data = this.safeValue(message, "data");
        Object marketId = this.safeString(message, "contract_code");
        if (Helpers.isTrue(Helpers.isEqual(marketId, null)))
        {
            marketId = this.safeString2(data, "contract_code", "symbol");
        }
        Object market = this.safeMarket(marketId);
        Object parsedOrder = null;
        if (Helpers.isTrue(!Helpers.isEqual(data, null)))
        {
            // spot updates
            Object eventType = this.safeString(data, "eventType");
            if (Helpers.isTrue(Helpers.isEqual(eventType, "trade")))
            {
                // when a spot order is filled we get an update message
                // with the trade info
                Object parsedTrade = this.parseOrderTrade(data, market);
                // inject trade in existing order by faking an order object
                Object orderId = this.safeString(parsedTrade, "order");
                Object trades = new java.util.ArrayList<Object>(java.util.Arrays.asList(parsedTrade));
                Object status = this.parseOrderStatus(this.safeString2(data, "orderStatus", "status", "closed"));
                Object filled = this.safeString(data, "execAmt");
                Object remaining = this.safeString(data, "remainAmt");
                final Object finalData = data;
                Object order = new java.util.HashMap<String, Object>() {{
                    put( "id", orderId );
                    put( "trades", trades );
                    put( "status", status );
                    put( "symbol", Helpers.GetValue(market, "symbol") );
                    put( "filled", HtxCore.this.parseNumber(filled) );
                    put( "remaining", HtxCore.this.parseNumber(remaining) );
                    put( "price", HtxCore.this.safeNumber(finalData, "orderPrice") );
                    put( "amount", HtxCore.this.safeNumber(finalData, "orderSize") );
                    put( "info", finalData );
                }};
                parsedOrder = order;
            } else
            {
                parsedOrder = this.parseWsOrder(data, market);
            }
        } else
        {
            // contract branch
            parsedOrder = this.parseWsOrder(message, market);
            Object rawTrades = this.safeValue(message, "trade", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object tradesLength = Helpers.getArrayLength(rawTrades);
            if (Helpers.isTrue(Helpers.isGreaterThan(tradesLength, 0)))
            {
                final Object finalMessageHash = messageHash;
                final Object finalMarketId = marketId;
                Object tradesObject = new java.util.HashMap<String, Object>() {{
                    put( "trades", rawTrades );
                    put( "ch", finalMessageHash );
                    put( "symbol", finalMarketId );
                }};
                // inject order params in every trade
                final Object finalParsedOrder = parsedOrder;
                Object extendTradeParams = new java.util.HashMap<String, Object>() {{
                    put( "order", HtxCore.this.safeString(finalParsedOrder, "id") );
                    put( "type", HtxCore.this.safeString(finalParsedOrder, "type") );
                    put( "side", HtxCore.this.safeString(finalParsedOrder, "side") );
                }};
                // trades arrive inside an order update
                // we're forwarding them to handleMyTrade
                // so they can be properly resolved
                this.handleMyTrade(client, tradesObject, extendTradeParams);
            }
        }
        if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
        {
            Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
            this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object cachedOrders = this.orders;
        Helpers.callDynamically(cachedOrders, "append", new Object[]{parsedOrder});
        client.resolve(this.orders, messageHash);
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(messageHash, "orders"))) && Helpers.isTrue((!Helpers.isEqual(marketId, null)))))
        {
            Object specificMessageHash = Helpers.add(Helpers.add(messageHash, "."), ((String)marketId).toLowerCase());
            client.resolve(this.orders, specificMessageHash);
        }
        // when we make a global subscription (for contracts only) our message hash can't have a symbol/currency attached
        // so we're removing it here
        Object genericMessageHash = Helpers.replace((String)messageHash, (String)Helpers.add(".", Helpers.GetValue(market, "lowercaseId")), (String)"");
        Object lowerCaseBaseId = this.safeStringLower(market, "baseId");
        genericMessageHash = Helpers.replace((String)genericMessageHash, (String)Helpers.add(".", lowerCaseBaseId), (String)"");
        client.resolve(this.orders, genericMessageHash);
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        // spot
        //
        //     {
        //         "orderSource": "spot-web",
        //         "orderCreateTime": 1645116048355, // creating only
        //         "accountId": 44234548,
        //         "orderPrice": "100",
        //         "orderSize": "0.05",
        //         "orderValue": "3.71676361", // market-buy only
        //         "symbol": "ethusdt",
        //         "type": "buy-limit",
        //         "orderId": "478861479986886",
        //         "eventType": "creation",
        //         "clientOrderId": '',
        //         "orderStatus": "submitted"
        //         "lastActTime":1645118621810 // except creating
        //         "execAmt":"0"
        //     }
        //
        // swap order
        //
        //     {
        //         "contract_type": "swap",
        //         "pair": "LTC-USDT",
        //         "business_type": "swap",
        //         "op": "notify",
        //         "topic": "orders_cross.ltc-usdt",
        //         "ts": 1648717911384,
        //         "symbol": "LTC",
        //         "contract_code": "LTC-USDT",
        //         "volume": 1,
        //         "price": 129.13,
        //         "order_price_type": "lightning",
        //         "direction": "sell",
        //         "offset": "close",
        //         "status": 6,
        //         "lever_rate": 5,
        //         "order_id": "959137967397068800",
        //         "order_id_str": "959137967397068800",
        //         "client_order_id": null,
        //         "order_source": "web",
        //         "order_type": 1,
        //         "created_at": 1648717911344,
        //         "trade_volume": 1,
        //         "trade_turnover": 12.952,
        //         "fee": -0.006476,
        //         "trade_avg_price": 129.52,
        //         "margin_frozen": 0,
        //         "profit": -0.005,
        //         "trade": [
        //             {
        //                 "trade_fee": -0.006476,
        //                 "fee_asset": "USDT",
        //                 "real_profit": -0.005,
        //                 "profit": -0.005,
        //                 "trade_id": 83619995370,
        //                 "id": "83619995370-959137967397068800-1",
        //                 "trade_volume": 1,
        //                 "trade_price": 129.52,
        //                 "trade_turnover": 12.952,
        //                 "created_at": 1648717911352,
        //                 "role": "taker"
        //             }
        //         ],
        //         "canceled_at": 0,
        //         "fee_asset": "USDT",
        //         "margin_asset": "USDT",
        //         "uid": "359305390",
        //         "liquidation_type": "0",
        //         "margin_mode": "cross",
        //         "margin_account": "USDT",
        //         "is_tpsl": 0,
        //         "real_profit": -0.005,
        //         "trade_partition": "USDT",
        //         "reduce_only": 1
        //     }
        //
        //     {
        //         "op":"notify",
        //         "topic":"orders.ada",
        //         "ts":1604388667226,
        //         "symbol":"ADA",
        //         "contract_type":"quarter",
        //         "contract_code":"ADA201225",
        //         "volume":1,
        //         "price":0.0905,
        //         "order_price_type":"post_only",
        //         "direction":"sell",
        //         "offset":"open",
        //         "status":6,
        //         "lever_rate":20,
        //         "order_id":773207641127878656,
        //         "order_id_str":"773207641127878656",
        //         "client_order_id":null,
        //         "order_source":"web",
        //         "order_type":1,
        //         "created_at":1604388667146,
        //         "trade_volume":1,
        //         "trade_turnover":10,
        //         "fee":-0.022099447513812154,
        //         "trade_avg_price":0.0905,
        //         "margin_frozen":0,
        //         "profit":0,
        //         "trade":[],
        //         "canceled_at":0,
        //         "fee_asset":"ADA",
        //         "uid":"123456789",
        //         "liquidation_type":"0",
        //         "is_tpsl": 0,
        //         "real_profit": 0
        //     }
        //
        // linear v5 watchOrders
        //
        //     {
        //         "side": "buy",
        //         "type": "limit",
        //         "price": "40000",
        //         "volume": "1",
        //         "state": "new",
        //         "profit": "0",
        //         "contract_code": "BTC-USDT",
        //         "position_side": "both",
        //         "price_match": null,
        //         "order_id": "1519705236917489664",
        //         "client_order_id": "1519705236917489664",
        //         "margin_mode": "cross",
        //         "lever_rate": 10,
        //         "order_source": "api",
        //         "reduce_only": false,
        //         "time_in_force": "gtc",
        //         "trade_avg_price": "0",
        //         "trade_volume": "0",
        //         "trade_turnover": "0",
        //         "fee_currency": null,
        //         "fee": "0",
        //         "tp_trigger_price": "",
        //         "tp_order_price": "",
        //         "tp_type": "",
        //         "tp_trigger_price_type": "",
        //         "sl_trigger_price": "",
        //         "sl_order_price": "",
        //         "sl_type": "",
        //         "sl_trigger_price_type": "",
        //         "contract_type": "swap",
        //         "cancel_reason": "",
        //         "created_time": "1782367563239",
        //         "updated_time": "1782367563239",
        //         "self_match_prevent": "cancel_taker",
        //         "amend_origin_volume": "",
        //         "amend_source": "",
        //         "amend_result": ""
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object lastTradeTimestamp = this.safeIntegerN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("lastActTime", "updated_time", "ts")));
        Object created = this.safeInteger2(order, "orderCreateTime", "created_time");
        Object marketId = this.safeString2(order, "contract_code", "symbol");
        market = this.safeMarket(marketId, market);
        Object symbol = this.safeSymbol(marketId, market);
        Object amount = this.safeString2(order, "orderSize", "volume");
        Object status = this.parseOrderStatus(this.safeStringN(order, new java.util.ArrayList<Object>(java.util.Arrays.asList("orderStatus", "state", "status"))));
        Object id = this.safeString2(order, "orderId", "order_id");
        Object clientOrderId = this.safeString2(order, "clientOrderId", "client_order_id");
        Object price = this.safeString2(order, "orderPrice", "price");
        Object filled = this.safeString2(order, "execAmt", "trade_volume");
        Object typeSide = this.safeString(order, "type");
        Object feeCost = this.safeString(order, "fee");
        Object fee = null;
        if (Helpers.isTrue(!Helpers.isEqual(feeCost, null)))
        {
            Object feeCurrencyId = this.safeString2(order, "fee_asset", "fee_currency");
            final Object finalFeeCost = feeCost;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCost );
                put( "currency", HtxCore.this.safeCurrencyCode(feeCurrencyId) );
            }};
        }
        Object avgPrice = this.safeString(order, "trade_avg_price");
        Object rawTrades = this.safeValue(order, "trade");
        Object typeSideParts = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object type = null;
        if (Helpers.isTrue(!Helpers.isEqual(typeSide, null)))
        {
            if (Helpers.isTrue(Helpers.isGreaterThanOrEqual(Helpers.getIndexOf(typeSide, "-"), 0)))
            {
                typeSideParts = Helpers.split(typeSide, "-");
                type = this.safeStringLower(typeSideParts, 1);
            } else
            {
                type = typeSide;
            }
        }
        if (Helpers.isTrue(Helpers.isEqual(type, null)))
        {
            type = this.safeString(order, "order_price_type");
        }
        Object side = this.safeStringLower(typeSideParts, 0);
        if (Helpers.isTrue(Helpers.isEqual(side, null)))
        {
            side = this.safeString2(order, "direction", "side");
        }
        Object cost = this.safeString2(order, "orderValue", "trade_turnover");
        final Object finalType = type;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "id", id );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", created );
            put( "datetime", HtxCore.this.iso8601(created) );
            put( "lastTradeTimestamp", lastTradeTimestamp );
            put( "status", status );
            put( "symbol", symbol );
            put( "type", finalType );
            put( "timeInForce", HtxCore.this.safeStringUpper(order, "time_in_force") );
            put( "postOnly", null );
            put( "side", finalSide );
            put( "price", price );
            put( "amount", amount );
            put( "filled", filled );
            put( "remaining", null );
            put( "cost", cost );
            put( "fee", finalFee );
            put( "average", avgPrice );
            put( "trades", rawTrades );
            put( "reduceOnly", HtxCore.this.safeBool(order, "reduce_only") );
            put( "stopPrice", null );
            put( "triggerPrice", null );
            put( "takeProfitPrice", HtxCore.this.safeString2(order, "tp_trigger_price", "tp_order_price") );
            put( "stopLossPrice", HtxCore.this.safeString2(order, "sl_trigger_price", "sl_order_price") );
        }}, market);
    }

    public Object parseOrderTrade(Object trade, Object... optionalArgs)
    {
        // spot private wrapped trade
        //
        //     {
        //         "tradePrice": "130.01",
        //         "tradeVolume": "0.0385",
        //         "tradeTime": 1648714741525,
        //         "aggressor": true,
        //         "execAmt": "0.0385",
        //         "orderSource": "spot-web",
        //         "orderSize": "0.0385",
        //         "remainAmt": "0",
        //         "tradeId": 101541578884,
        //         "symbol": "ltcusdt",
        //         "type": "sell-market",
        //         "eventType": "trade",
        //         "clientOrderId": '',
        //         "orderStatus": "filled",
        //         "orderId": 509835753860328
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        market = this.safeMarket(null, market);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object tradeId = this.safeString(trade, "tradeId");
        Object price = this.safeString(trade, "tradePrice");
        Object amount = this.safeString(trade, "tradeVolume");
        Object order = this.safeString(trade, "orderId");
        Object timestamp = this.safeInteger(trade, "tradeTime");
        Object type = this.safeString(trade, "type");
        Object side = null;
        if (Helpers.isTrue(!Helpers.isEqual(type, null)))
        {
            Object typeParts = Helpers.split(type, "-");
            side = Helpers.GetValue(typeParts, 0);
            type = Helpers.GetValue(typeParts, 1);
        }
        Object aggressor = this.safeValue(trade, "aggressor");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(aggressor, null)))
        {
            takerOrMaker = ((Helpers.isTrue(aggressor))) ? "taker" : "maker";
        }
        final Object finalType = type;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalSide = side;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", HtxCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "id", tradeId );
            put( "order", order );
            put( "type", finalType );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "side", finalSide );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", null );
        }}, market);
    }

    /**
     * @method
     * @name htx#watchPositions
     * @description watch all open positions. Note: huobi has one channel for each marginMode and type
     * @see https://www.huobi.com/en-in/opend/newApiPages/?id=28c34a7d-77ae-11ed-9966-0242ac110003
     * @see https://www.huobi.com/en-in/opend/newApiPages/?id=5d5156b5-77b6-11ed-9966-0242ac110003
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=8cb89359-77b5-11ed-9966-195a35d6034
     * @param {string[]} [symbols] list of unified market symbols
     * @param {int} [since] timestamp in ms of the earliest position to fetch
     * @param {int} [limit] the maximum number of positions to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/en/latest/manual.html#position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = null;
            Object messageHash = "";
            if (!Helpers.isTrue(this.isEmpty(symbols)))
            {
                market = this.getMarketFromSymbols(symbols);
                messageHash = Helpers.add("::", String.join((String)",", (java.util.List<String>)symbols));
            }
            Object type = null;
            Object subType = null;
            if (Helpers.isTrue(!Helpers.isEqual(market, null)))
            {
                type = Helpers.GetValue(market, "type");
                subType = ((Helpers.isTrue(Helpers.GetValue(market, "linear")))) ? "linear" : "inverse";
            } else
            {
                var typeparametersVariable = this.handleMarketTypeAndParams("watchPositions", market, parameters);
                type = ((java.util.List<Object>) typeparametersVariable).get(0);
                parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
                if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                {
                    type = "future";
                }
                var subTypeparametersVariable = this.handleOptionAndParams(parameters, "watchPositions", "subType", subType);
                subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
                parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            }
            symbols = this.marketSymbols(symbols);
            Object marginMode = null;
            var marginModeparametersVariable = this.handleMarginModeAndParams("watchPositions", parameters, "cross");
            marginMode = ((java.util.List<Object>) marginModeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) marginModeparametersVariable).get(1);
            Object linear = (Helpers.isEqual(subType, "linear"));
            Object swap = (Helpers.isEqual(type, "swap"));
            Object future = (Helpers.isEqual(type, "future"));
            Object isV5Linear = (Helpers.isTrue(linear) && Helpers.isTrue((Helpers.isTrue(swap) || Helpers.isTrue(future))));
            Object isLinear = (Helpers.isEqual(subType, "linear"));
            Object url = this.getUrlByMarketType(type, isLinear, true, false, isV5Linear);
            messageHash = Helpers.add(Helpers.add(marginMode, ":positions"), messageHash);
            Object channel = ((Helpers.isTrue((Helpers.isEqual(marginMode, "cross"))))) ? "positions_cross.*" : "positions.*";
            if (Helpers.isTrue(isV5Linear))
            {
                Object isOneMarket = (!Helpers.isTrue(this.isEmpty(symbols)) && Helpers.isTrue((Helpers.isEqual(Helpers.getArrayLength(symbols), 1))));
                Object v5Market = ((Helpers.isTrue(isOneMarket))) ? market : null;
                Object channelAndMessageHashAndParams = this.getV5LinearChannelAndMessageHash("positions", v5Market, parameters);
                channel = this.safeString(channelAndMessageHashAndParams, 0);
                parameters = this.safeValue(channelAndMessageHashAndParams, 2, new java.util.HashMap<String, Object>() {{}});
            }
            final Object finalMarginMode = marginMode;
            Object subscriptionParams = new java.util.HashMap<String, Object>() {{
                put( "isV5", isV5Linear );
                put( "margin", finalMarginMode );
            }};
            Object newPositions = (this.subscribePrivate(channel, messageHash, type, subType, parameters, subscriptionParams)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return newPositions;
            }
            return this.filterBySymbolsSinceLimit(Helpers.GetValue(Helpers.GetValue(this.positions, url), marginMode), symbols, since, limit, false);
        });

    }

    public void handlePositions(Client client, Object message)
    {
        //
        //    {
        //        op: 'notify',
        //        topic: 'positions_cross',
        //        ts: 1696767149650,
        //        event: 'snapshot',
        //        data: [
        //          {
        //            contract_type: 'swap',
        //            pair: 'BTC-USDT',
        //            business_type: 'swap',
        //            liquidation_price: null,
        //            symbol: 'BTC',
        //            contract_code: 'BTC-USDT',
        //            volume: 1,
        //            available: 1,
        //            frozen: 0,
        //            cost_open: 27802.2,
        //            cost_hold: 27802.2,
        //            profit_unreal: 0.0175,
        //            profit_rate: 0.000629446590557581,
        //            profit: 0.0175,
        //            margin_asset: 'USDT',
        //            position_margin: 27.8197,
        //            lever_rate: 1,
        //            direction: 'buy',
        //            last_price: 27819.7,
        //            margin_mode: 'cross',
        //            margin_account: 'USDT',
        //            trade_partition: 'USDT',
        //            position_mode: 'dual_side'
        //          },
        //        ]
        //    }
        //
        // watchPositions linear v5
        //
        //     {
        //         "op": "notify",
        //         "topic": "positions",
        //         "contract_code": "BTC-USDT",
        //         "ts": 1782460576073,
        //         "uid": "359305390",
        //         "event": "snapshot",
        //         "data": [
        //             {
        //                 "contract_code": "BTC-USDT",
        //                 "symbol": "BTC",
        //                 "position_mode": "single_side",
        //                 "position_side": "both",
        //                 "direction": "buy",
        //                 "margin_mode": "cross",
        //                 "open_avg_price": "60547.9",
        //                 "volume": "1",
        //                 "available": "1",
        //                 "fee": "0.03632874",
        //                 "break_even_price": "60620.55748",
        //                 "total_trade_fee": "0.03632874",
        //                 "lever_rate": 10,
        //                 "adl_risk_percent": 4,
        //                 "liquidation_price": "-102094.847680676304309652",
        //                 "initial_margin": "6.05807",
        //                 "maintenance_margin": "0.20597438",
        //                 "profit_unreal": "0.0328",
        //                 "profit": "0",
        //                 "profit_rate": "0.0054",
        //                 "margin_rate": "0.0012",
        //                 "state": "normal",
        //                 "funding_fee": "0",
        //                 "mark_price": "60580.7",
        //                 "last_price": "60591.4",
        //                 "contract_type": "swap",
        //                 "version": 7,
        //                 "created_time": "1782460515119",
        //                 "updated_time": "1782460515119"
        //             }
        //         ]
        //     }
        //
        Object url = client.url;
        Object topic = this.safeString(message, "topic", "");
        Object defaultMarginMode = ((Helpers.isTrue((Helpers.isEqual(topic, "positions_cross"))))) ? "cross" : "isolated";
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new java.util.HashMap<String, Object>() {{}};
        }
        Object clientPositions = this.safeValue(this.positions, url);
        if (Helpers.isTrue(Helpers.isEqual(clientPositions, null)))
        {
            Helpers.addElementToObject(this.positions, url, new java.util.HashMap<String, Object>() {{}});
        }
        Object rawPositions = this.safeValue(message, "data", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(this.isEmpty(rawPositions)))
        {
            Object prefixes = new java.util.ArrayList<Object>(java.util.Arrays.asList("cross:positions", "isolated:positions"));
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(prefixes)); i++)
            {
                Object messageHashes = this.findMessageHashes(client, Helpers.GetValue(prefixes, i));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(messageHashes)); j++)
                {
                    client.resolve(new java.util.ArrayList<Object>(java.util.Arrays.asList()), Helpers.GetValue(messageHashes, j));
                }
            }
            return;
        }
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        Object positionsByMarginMode = new java.util.HashMap<String, Object>() {{}};
        Object timestamp = this.safeInteger(message, "ts");
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawPositions)); i++)
        {
            Object rawPosition = Helpers.GetValue(rawPositions, i);
            Object position = this.parsePosition(rawPosition);
            Helpers.addElementToObject(position, "timestamp", timestamp);
            Helpers.addElementToObject(position, "datetime", this.iso8601(timestamp));
            Object marginMode = this.safeStringLower(position, "marginMode", defaultMarginMode);
            if (Helpers.isTrue(Helpers.isTrue((!Helpers.isEqual(marginMode, "cross"))) && Helpers.isTrue((!Helpers.isEqual(marginMode, "isolated")))))
            {
                marginMode = defaultMarginMode;
            }
            Object cache = this.safeValue(Helpers.GetValue(this.positions, url), marginMode);
            if (Helpers.isTrue(Helpers.isEqual(cache, null)))
            {
                cache = new ArrayCache.ArrayCacheBySymbolBySide();
                Helpers.addElementToObject(Helpers.GetValue(this.positions, url), marginMode, cache);
            }
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.addElementToObject(positionsByMarginMode, marginMode, this.safeValue(positionsByMarginMode, marginMode, new java.util.ArrayList<Object>(java.util.Arrays.asList())));
            ((java.util.List<Object>)Helpers.GetValue(positionsByMarginMode, marginMode)).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
        }
        Object marginModes = Helpers.objectKeys(positionsByMarginMode);
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(marginModes)); i++)
        {
            Object marginMode = Helpers.GetValue(marginModes, i);
            Object marginModePositions = this.safeValue(positionsByMarginMode, marginMode, new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object messageHashes = this.findMessageHashes(client, Helpers.add(marginMode, ":positions::"));
            for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(messageHashes)); j++)
            {
                Object messageHash = Helpers.GetValue(messageHashes, j);
                Object parts = Helpers.split(messageHash, "::");
                Object symbolsString = Helpers.GetValue(parts, 1);
                Object symbols = Helpers.split(symbolsString, ",");
                Object positions = this.filterByArray(marginModePositions, "symbol", symbols, false);
                if (!Helpers.isTrue(this.isEmpty(positions)))
                {
                    client.resolve(positions, messageHash);
                }
            }
            client.resolve(marginModePositions, Helpers.add(marginMode, ":positions"));
        }
    }

    /**
     * @method
     * @name htx#watchBalance
     * @description watch balance and get the amount of funds available for trading or funds locked in orders
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=7ec52e28-7773-11ed-9966-0242ac110003
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=28c34995-77ae-11ed-9966-0242ac110003
     * @see https://www.htx.com/en-us/opend/newApiPages/?id=8cb89359-77b5-11ed-9966-195a6c94551
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object type = null;
            var typeparametersVariable = this.handleMarketTypeAndParams("watchBalance", null, parameters);
            type = ((java.util.List<Object>) typeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) typeparametersVariable).get(1);
            Object subType = null;
            var subTypeparametersVariable = this.handleSubTypeAndParams("watchBalance", null, parameters, "linear");
            subType = ((java.util.List<Object>) subTypeparametersVariable).get(0);
            parameters = ((java.util.List<Object>) subTypeparametersVariable).get(1);
            Object isUnifiedAccount = this.safeValue2(parameters, "isUnifiedAccount", "unified", false);
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("isUnifiedAccount", "unified")));
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object messageHash = null;
            Object channel = null;
            Object marginMode = null;
            Object linear = (Helpers.isEqual(subType, "linear"));
            Object swap = (Helpers.isEqual(type, "swap"));
            Object future = (Helpers.isEqual(type, "future"));
            Object isV5Linear = (Helpers.isTrue(linear) && Helpers.isTrue((Helpers.isTrue(swap) || Helpers.isTrue(future))));
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                Object mode = this.safeString2(this.options, "watchBalance", "mode", "2");
                mode = this.safeString(parameters, "mode", mode);
                messageHash = Helpers.add(Helpers.add("accounts.update", "#"), mode);
                channel = messageHash;
            } else if (Helpers.isTrue(isV5Linear))
            {
                marginMode = this.safeString(parameters, "margin", "cross");
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("currency", "symbol", "margin")));
                channel = "account";
                messageHash = "account";
            } else
            {
                Object symbol = this.safeString(parameters, "symbol");
                Object currency = this.safeString(parameters, "currency");
                Object market = ((Helpers.isTrue((!Helpers.isEqual(symbol, null))))) ? this.market(symbol) : null;
                Object currencyCode = ((Helpers.isTrue((!Helpers.isEqual(currency, null))))) ? this.currency(currency) : null;
                marginMode = this.safeString(parameters, "margin", "cross");
                parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("currency", "symbol", "margin")));
                Object prefix = "accounts";
                messageHash = prefix;
                if (Helpers.isTrue(Helpers.isEqual(subType, "linear")))
                {
                    if (Helpers.isTrue(isUnifiedAccount))
                    {
                        // usdt contracts account
                        prefix = "accounts_unify";
                        messageHash = prefix;
                        channel = Helpers.add(Helpers.add(prefix, "."), "usdt");
                    } else
                    {
                        // usdt contracts account
                        prefix = ((Helpers.isTrue((Helpers.isEqual(marginMode, "cross"))))) ? Helpers.add(prefix, "_cross") : prefix;
                        messageHash = prefix;
                        if (Helpers.isTrue(Helpers.isEqual(marginMode, "isolated")))
                        {
                            // isolated margin only allows filtering by symbol3
                            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                            {
                                messageHash = Helpers.add(messageHash, Helpers.add(".", Helpers.GetValue(market, "id")));
                                channel = messageHash;
                            } else
                            {
                                // subscribe to all
                                channel = Helpers.add(Helpers.add(prefix, "."), "*");
                            }
                        } else
                        {
                            // cross margin
                            if (Helpers.isTrue(!Helpers.isEqual(currencyCode, null)))
                            {
                                channel = Helpers.add(Helpers.add(prefix, "."), Helpers.GetValue(currencyCode, "id"));
                                messageHash = channel;
                            } else
                            {
                                // subscribe to all
                                channel = Helpers.add(Helpers.add(prefix, "."), "*");
                            }
                        }
                    }
                } else if (Helpers.isTrue(Helpers.isEqual(type, "future")))
                {
                    // inverse futures account
                    if (Helpers.isTrue(!Helpers.isEqual(currencyCode, null)))
                    {
                        messageHash = Helpers.add(messageHash, Helpers.add(".", Helpers.GetValue(currencyCode, "id")));
                        channel = messageHash;
                    } else
                    {
                        // subscribe to all
                        channel = Helpers.add(Helpers.add(prefix, "."), "*");
                    }
                } else
                {
                    // inverse swaps account
                    if (Helpers.isTrue(!Helpers.isEqual(market, null)))
                    {
                        messageHash = Helpers.add(messageHash, Helpers.add(".", Helpers.GetValue(market, "id")));
                        channel = messageHash;
                    } else
                    {
                        // subscribe to all
                        channel = Helpers.add(Helpers.add(prefix, "."), "*");
                    }
                }
            }
            final Object finalType = type;
            final Object finalSubType = subType;
            final Object finalMarginMode = marginMode;
            Object subscriptionParams = new java.util.HashMap<String, Object>() {{
                put( "type", finalType );
                put( "subType", finalSubType );
                put( "margin", finalMarginMode );
                put( "isV5", isV5Linear );
            }};
            // we are differentiating the channel from the messageHash for global subscriptions (*)
            // because huobi returns a different topic than the topic sent. Example: we send
            // "accounts.*" and "accounts" is returned so we're setting channel = "accounts.*" and
            // messageHash = "accounts" allowing handleBalance to freely resolve the topic in the message
            return (this.subscribePrivate(channel, messageHash, type, subType, parameters, subscriptionParams)).join();
        });

    }

