    public Object handleErrorMessage(Client client, Object message)
    {
        //
        //     {
        //         "action": "sub",
        //         "code": 2002,
        //         "ch": "accounts.update#2",
        //         "message": "invalid.auth.state"
        //      }
        //
        //     {
        //         "ts": 1586323747018,
        //         "status": "error",
        //         'err-code': "bad-request",
        //         'err-msg': "invalid mbp.150.symbol linkusdt",
        //         "id": "2"
        //     }
        //
        //     {
        //         "op": "sub",
        //         "cid": "1",
        //         "topic": "accounts_unify.USDT",
        //         "err-code": 4007,
        //         'err-msg': "Non - single account user is not available, please check through the cross and isolated account asset interface",
        //         "ts": 1698419490189
        //     }
        //     {
        //         "action":"req",
        //         "code":2002,
        //         "ch":"auth",
        //         "message":"auth.fail"
        //     }
        //
        Object status = this.safeString(message, "status");
        if (Helpers.isTrue(Helpers.isEqual(status, "error")))
        {
            Object id = this.safeString(message, "id");
            Object subscriptionsById = this.indexBy(client.subscriptions, "id");
            Object subscription = this.safeValue(subscriptionsById, id);
            if (Helpers.isTrue(!Helpers.isEqual(subscription, null)))
            {
                Object errorCode = this.safeString(message, "err-code");
                try
                {
                    this.throwExactlyMatchedException(Helpers.GetValue(Helpers.GetValue(this.exceptions, "ws"), "exact"), errorCode, this.json(message));
                    throw new ExchangeError((String)this.json(message)) ;
                } catch(Exception e)
                {
                    Object messageHash = this.safeString(subscription, "messageHash");
                    client.reject(e, messageHash);
                    client.reject(e, id);
                    if (Helpers.isTrue(Helpers.inOp(client.subscriptions, id)))
                    {
                        ((java.util.Map<String,Object>)client.subscriptions).remove((String)id);
                    }
                }
            }
            return false;
        }
        Object code = this.safeString2(message, "code", "err-code");
        if (Helpers.isTrue(Helpers.isTrue(!Helpers.isEqual(code, null)) && Helpers.isTrue((Helpers.isTrue((!Helpers.isEqual(code, "200"))) && Helpers.isTrue((!Helpers.isEqual(code, "0")))))))
        {
            Object feedback = Helpers.add(Helpers.add(this.id, " "), this.json(message));
            try
            {
                this.throwExactlyMatchedException(Helpers.GetValue(Helpers.GetValue(this.exceptions, "ws"), "exact"), code, feedback);
                throw new ExchangeError((String)feedback) ;
            } catch(Exception e)
            {
                if (Helpers.isTrue(Helpers.isInstance(e, AuthenticationError.class)))
                {
                    client.reject(e, "auth");
                    Object method = "auth";
                    if (Helpers.isTrue(Helpers.inOp(client.subscriptions, method)))
                    {
                        ((java.util.Map<String,Object>)client.subscriptions).remove((String)method);
                    }
                    return false;
                } else
                {
                    client.reject(e);
                }
            }
        }
        return true;
    }

    public void handleMessage(Client client, Object message)
    {
        if (Helpers.isTrue(this.handleErrorMessage(client, message)))
        {
            //
            //     {"id":1583414227,"status":"ok","subbed":"market.btcusdt.mbp.150","ts":1583414229143}
            //
            // first ping format
            //
            //    {"ping": 1645106821667 }
            //
            // second ping format
            //
            //    {"action":"ping","data":{"ts":1645106821667}}
            //
            // third pong format
            //
            //
            // auth spot
            //
            //     {
            //         "action": "req",
            //         "code": 200,
            //         "ch": "auth",
            //         "data": {}
            //     }
            //
            // auth non spot
            //
            //    {
            //        "op": "auth",
            //        "type": "api",
            //        "err-code": 0,
            //        "ts": 1645200307319,
            //        "data": { "user-id": "35930539" }
            //    }
            //
            // trade
            //
            //     {
            //         "action":"push",
            //         "ch":"trade.clearing#ltcusdt#1",
            //         "data":{
            //             "eventType":"trade",
            //             // ?
            //         }
            //     }
            //
            if (Helpers.isTrue(Helpers.inOp(message, "id")))
            {
                this.handleSubscriptionStatus(client, message);
                return;
            }
            if (Helpers.isTrue(Helpers.inOp(message, "action")))
            {
                Object action = this.safeString(message, "action");
                if (Helpers.isTrue(Helpers.isEqual(action, "ping")))
                {
                    this.handlePing(client, message);
                    return;
                }
                if (Helpers.isTrue(Helpers.isEqual(action, "sub")))
                {
                    this.handleSubscriptionStatus(client, message);
                    return;
                }
            }
            if (Helpers.isTrue(Helpers.inOp(message, "ch")))
            {
                if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(message, "ch"), "auth")))
                {
                    this.handleAuthenticate(client, message);
                    return;
                } else
                {
                    // route by channel aka topic aka subject
                    this.handleSubject(client, message);
                    return;
                }
            }
            if (Helpers.isTrue(Helpers.inOp(message, "op")))
            {
                Object op = this.safeString(message, "op");
                if (Helpers.isTrue(Helpers.isEqual(op, "ping")))
                {
                    this.handlePing(client, message);
                    return;
                }
                if (Helpers.isTrue(Helpers.isEqual(op, "auth")))
                {
                    this.handleAuthenticate(client, message);
                    return;
                }
                if (Helpers.isTrue(Helpers.isEqual(op, "sub")))
                {
                    this.handleSubscriptionStatus(client, message);
                    return;
                }
                if (Helpers.isTrue(Helpers.isEqual(op, "notify")))
                {
                    this.handleSubject(client, message);
                    return;
                }
            }
            if (Helpers.isTrue(Helpers.inOp(message, "ping")))
            {
                this.handlePing(client, message);
            }
        }
    }

    public void handleMyTrade(Client client, Object message, Object... optionalArgs)
    {
        //
        // spot
        //
        //     {
        //         "action":"push",
        //         "ch":"trade.clearing#ltcusdt#1",
        //         "data":{
        //             "eventType":"trade",
        //             "symbol":"ltcusdt",
        //             "orderId":"478862728954426",
        //             "orderSide":"buy",
        //             "orderType":"buy-market",
        //             "accountId":44234548,
        //             "source":"spot-web",
        //             "orderValue":"5.01724137",
        //             "orderCreateTime":1645124660365,
        //             "orderStatus":"filled",
        //             "feeCurrency":"ltc",
        //             "tradePrice":"118.89",
        //             "tradeVolume":"0.042200701236437042",
        //             "aggressor":true,
        //             "tradeId":101539740584,
        //             "tradeTime":1645124660368,
        //             "transactFee":"0.000041778694224073",
        //             "feeDeduct":"0",
        //             "feeDeductType":""
        //         }
        //     }
        //
        // contract
        //
        //     {
        //         "symbol": "ADA/USDT:USDT"
        //         "ch": "orders_cross.ada-usdt"
        //         "trades": [
        //             {
        //                 "trade_fee":-0.022099447513812154,
        //                 "fee_asset":"ADA",
        //                 "trade_id":113913755890,
        //                 "id":"113913755890-773207641127878656-1",
        //                 "trade_volume":1,
        //                 "trade_price":0.0905,
        //                 "trade_turnover":10,
        //                 "created_at":1604388667194,
        //                 "profit":0,
        //                 "real_profit": 0,
        //                 "role":"maker"
        //             }
        //         ],
        //     }
        //
        // linear v5 watchMyTrades
        //
        //     {
        //         "op": "notify",
        //         "topic": "trade",
        //         "contract_code": "BTC-USDT",
        //         "ts": 1782367694387,
        //         "uid": "359305390",
        //         "data": [
        //             {
        //                 "direction": "buy",
        //                 "id": "100121555172810-1519705786942156810-1",
        //                 "contract_code": "BTC-USDT",
        //                 "contract_type": "swap",
        //                 "order_id": "1519705786942156810",
        //                 "trade_id": "155233460",
        //                 "position_side": "both",
        //                 "trade_volume": "1",
        //                 "trade_price": "61629",
        //                 "trade_turnover": "61.629",
        //                 "role": "taker",
        //                 "client_order_id": "1519705786942156810",
        //                 "created_time": "1782367694375",
        //                 "updated_time": "1782367694385"
        //             }
        //         ]
        //     }
        //
        Object extendParams = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
        if (Helpers.isTrue(Helpers.isEqual(this.myTrades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            this.myTrades = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object cachedTrades = this.myTrades;
        Object messageHash = this.safeString2(message, "ch", "topic");
        if (Helpers.isTrue(!Helpers.isEqual(messageHash, null)))
        {
            Object data = this.safeValue(message, "data");
            if (Helpers.isTrue(!Helpers.isEqual(data, null)))
            {
                Object contractCode = this.safeString(message, "contract_code");
                Object market = ((Helpers.isTrue((!Helpers.isEqual(contractCode, null))))) ? this.safeMarket(contractCode) : null;
                if (Helpers.isTrue(Helpers.isArray(data)))
                {
                    for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
                    {
                        Object parsed = this.parseWsTrade(Helpers.GetValue(data, i), market);
                        Object symbol = this.safeString(parsed, "symbol");
                        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                        {
                            Helpers.callDynamically(cachedTrades, "append", new Object[]{parsed});
                        }
                    }
                } else
                {
                    Object parsed = this.parseWsTrade(data, market);
                    Object symbol = this.safeString(parsed, "symbol");
                    if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
                    {
                        Helpers.callDynamically(cachedTrades, "append", new Object[]{parsed});
                    }
                }
                client.resolve(this.myTrades, messageHash);
                if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(messageHash, "trade"))) && Helpers.isTrue((!Helpers.isEqual(contractCode, null)))))
                {
                    Object specificMessageHash = Helpers.add(Helpers.add(messageHash, "."), ((String)contractCode).toLowerCase());
                    client.resolve(this.myTrades, specificMessageHash);
                }
            } else
            {
                // this trades object is artificially created
                // in handleOrder
                Object rawTrades = this.safeValue(message, "trades", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object marketId = this.safeValue(message, "symbol");
                Object market = this.market(marketId);
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawTrades)); i++)
                {
                    Object trade = Helpers.GetValue(rawTrades, i);
                    Object parsedTrade = this.parseTrade(trade, market);
                    // add extra params (side, type, ...) coming from the order
                    parsedTrade = this.extend(parsedTrade, extendParams);
                    Helpers.callDynamically(cachedTrades, "append", new Object[]{parsedTrade});
                }
                // messageHash here is the orders one, so
                // we have to recreate the trades messageHash = orderMessageHash + ':' + 'trade'
                Object tradesHash = Helpers.add(Helpers.add(messageHash, ":"), "trade");
                client.resolve(this.myTrades, tradesHash);
                // when we make an global order sub we have to send the channel like this
                // ch = orders_cross.* and we store messageHash = 'orders_cross'
                // however it is returned with the specific order update symbol: ch = orders_cross.btc-usd
                // since this is a global sub, our messageHash does not specify any symbol (ex: orders_cross:trade)
                // so we must remove it
                Object genericOrderHash = Helpers.replace((String)messageHash, (String)Helpers.add(".", Helpers.GetValue(market, "lowercaseId")), (String)"");
                Object lowerCaseBaseId = this.safeStringLower(market, "baseId");
                genericOrderHash = Helpers.replace((String)genericOrderHash, (String)Helpers.add(".", lowerCaseBaseId), (String)"");
                Object genericTradesHash = Helpers.add(Helpers.add(genericOrderHash, ":"), "trade");
                client.resolve(this.myTrades, genericTradesHash);
            }
        }
    }

    public Object parseWsTrade(Object trade, Object... optionalArgs)
    {
        // spot private
        //
        //     {
        //         "eventType":"trade",
        //         "symbol":"ltcusdt",
        //         "orderId":"478862728954426",
        //         "orderSide":"buy",
        //         "orderType":"buy-market",
        //         "accountId":44234548,
        //         "source":"spot-web",
        //         "orderValue":"5.01724137",
        //         "orderCreateTime":1645124660365,
        //         "orderStatus":"filled",
        //         "feeCurrency":"ltc",
        //         "tradePrice":"118.89",
        //         "tradeVolume":"0.042200701236437042",
        //         "aggressor":true,
        //         "tradeId":101539740584,
        //         "tradeTime":1645124660368,
        //         "transactFee":"0.000041778694224073",
        //         "feeDeduct":"0",
        //         "feeDeductType":""
        //     }
        //
        // linear v5 watchMyTrades
        //
        //     {
        //         "direction": "buy",
        //         "id": "100121555172810-1519705786942156810-1",
        //         "contract_code": "BTC-USDT",
        //         "contract_type": "swap",
        //         "order_id": "1519705786942156810",
        //         "trade_id": "155233460",
        //         "position_side": "both",
        //         "trade_volume": "1",
        //         "trade_price": "61629",
        //         "trade_turnover": "61.629",
        //         "role": "taker",
        //         "client_order_id": "1519705786942156810",
        //         "created_time": "1782367694375",
        //         "updated_time": "1782367694385"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object marketId = this.safeString2(trade, "symbol", "contract_code");
        market = this.safeMarket(marketId, market);
        Object symbol = this.safeString(market, "symbol");
        Object side = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("side", "orderSide", "direction")));
        Object tradeId = this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("tradeId", "trade_id", "id")));
        Object price = this.safeString2(trade, "tradePrice", "trade_price");
        Object amount = this.safeString2(trade, "tradeVolume", "trade_volume");
        Object order = this.safeString2(trade, "orderId", "order_id");
        Object timestamp = this.safeIntegerN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("tradeTime", "updated_time", "created_time")));
        Object orderType = this.safeString2(trade, "orderType", "type");
        Object aggressor = this.safeValue(trade, "aggressor");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(aggressor, null)))
        {
            takerOrMaker = ((Helpers.isTrue(aggressor))) ? "taker" : "maker";
        } else
        {
            takerOrMaker = this.safeStringLower(trade, "role");
        }
        Object type = null;
        Object orderTypeParts = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        if (Helpers.isTrue(!Helpers.isEqual(orderType, null)))
        {
            orderTypeParts = Helpers.split(orderType, "-");
            type = this.safeString(orderTypeParts, 1, orderType);
        }
        Object fee = null;
        Object feeCurrency = this.safeCurrencyCode(this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("feeCurrency", "fee_currency", "fee_asset"))));
        if (Helpers.isTrue(!Helpers.isEqual(feeCurrency, null)))
        {
            final Object finalFeeCurrency = feeCurrency;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", HtxCore.this.safeStringN(trade, new java.util.ArrayList<Object>(java.util.Arrays.asList("transactFee", "fee", "trade_fee"))) );
                put( "currency", finalFeeCurrency );
            }};
        }
        final Object finalType = type;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", HtxCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "id", tradeId );
            put( "order", order );
            put( "type", finalType );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "side", side );
            put( "price", price );
            put( "amount", amount );
            put( "cost", null );
            put( "fee", finalFee );
        }}, market);
    }

    public Object getUrlByMarketType(Object type, Object... optionalArgs)
    {
        Object isLinear = Helpers.getArg(optionalArgs, 0, true);
        Object isPrivate = Helpers.getArg(optionalArgs, 1, false);
        Object isFeed = Helpers.getArg(optionalArgs, 2, false);
        Object isV5 = Helpers.getArg(optionalArgs, 3, false);
        Object api = this.safeString(this.options, "api", "api");
        Object hostname = new java.util.HashMap<String, Object>() {{
            put( "hostname", HtxCore.this.hostname );
        }};
        Object hostnameURL = null;
        Object url = null;
        if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
        {
            if (Helpers.isTrue(isPrivate))
            {
                hostnameURL = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), api), "spot"), "private");
            } else
            {
                if (Helpers.isTrue(isFeed))
                {
                    hostnameURL = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), api), "spot"), "feed");
                } else
                {
                    hostnameURL = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), api), "spot"), "public");
                }
            }
            url = this.implodeParams(hostnameURL, hostname);
        } else
        {
            Object baseUrl = Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), api), type);
            Object subTypeUrl = ((Helpers.isTrue(isLinear))) ? Helpers.GetValue(baseUrl, "linear") : Helpers.GetValue(baseUrl, "inverse");
            if (Helpers.isTrue(isPrivate))
            {
                if (Helpers.isTrue(Helpers.isTrue(isV5) && Helpers.isTrue(isLinear)))
                {
                    url = this.safeString(subTypeUrl, "privateV5", Helpers.GetValue(subTypeUrl, "private"));
                } else
                {
                    url = Helpers.GetValue(subTypeUrl, "private");
                }
            } else
            {
                url = Helpers.GetValue(subTypeUrl, "public");
            }
        }
        return url;
    }

    public java.util.concurrent.CompletableFuture<Object> subscribePublic(Object url, Object symbol, Object messageHash, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object method = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object requestId = this.requestId();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "sub", messageHash );
                put( "id", requestId );
            }};
            Object subscription = new java.util.HashMap<String, Object>() {{
                put( "id", requestId );
                put( "messageHash", messageHash );
                put( "symbol", symbol );
                put( "params", parameters );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(method, null)))
            {
                Helpers.addElementToObject(subscription, "method", method);
            }
            return (this.watch(url, messageHash, this.extend(request, parameters), messageHash, subscription)).join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> unsubscribePublic(Object market, Object subMessageHash, Object topic2, Object... optionalArgs)
    {
        final Object topic3 = topic2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object topic = topic3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object requestId = this.requestId();
            Object request = new java.util.HashMap<String, Object>() {{
                put( "unsub", subMessageHash );
                put( "id", requestId );
            }};
            Object messageHash = Helpers.add("unsubscribe::", subMessageHash);
            Object isFeed = (Helpers.isEqual(topic, "orderbook"));
            Object url = this.getUrlByMarketType(Helpers.GetValue(market, "type"), Helpers.GetValue(market, "linear"), false, isFeed);
            final Object finalTopic = topic;
            Object subscription = new java.util.HashMap<String, Object>() {{
                put( "unsubscribe", true );
                put( "id", requestId );
                put( "subMessageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList(subMessageHash)) );
                put( "messageHashes", new java.util.ArrayList<Object>(java.util.Arrays.asList(messageHash)) );
                put( "symbols", new java.util.ArrayList<Object>(java.util.Arrays.asList(Helpers.GetValue(market, "symbol"))) );
                put( "topic", finalTopic );
            }};
            Object symbolsAndTimeframes = this.safeList(parameters, "symbolsAndTimeframes");
            if (Helpers.isTrue(!Helpers.isEqual(symbolsAndTimeframes, null)))
            {
                Helpers.addElementToObject(subscription, "symbolsAndTimeframes", symbolsAndTimeframes);
                parameters = this.omit(parameters, "symbolsAndTimeframes");
            }
            return (this.watch(url, messageHash, this.extend(request, parameters), messageHash, subscription)).join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> subscribePrivate(Object channel, Object messageHash, Object type2, Object subtype2, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object subtype3 = subtype2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object subtype = subtype3;
            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object subscriptionParams = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            Object requestId = this.requestId();
            Object subscription = new java.util.HashMap<String, Object>() {{
                put( "id", requestId );
                put( "messageHash", messageHash );
                put( "params", parameters );
            }};
            Object extendedSubsription = this.extend(subscription, subscriptionParams);
            Object request = null;
            if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
            {
                request = new java.util.HashMap<String, Object>() {{
                    put( "action", "sub" );
                    put( "ch", channel );
                }};
            } else
            {
                request = new java.util.HashMap<String, Object>() {{
                    put( "op", "sub" );
                    put( "topic", channel );
                    put( "cid", requestId );
                }};
            }
            Object isLinear = Helpers.isEqual(subtype, "linear");
            Object isV5 = this.safeBool(subscriptionParams, "isV5", false);
            Object url = this.getUrlByMarketType(type, isLinear, true, false, isV5);
            Object hostname = ((Helpers.isTrue((Helpers.isEqual(type, "spot"))))) ? Helpers.GetValue(Helpers.GetValue(this.urls, "hostnames"), "spot") : Helpers.GetValue(Helpers.GetValue(this.urls, "hostnames"), "contract");
            final Object finalType = type;
            Object authParams = new java.util.HashMap<String, Object>() {{
                put( "type", finalType );
                put( "url", url );
                put( "hostname", hostname );
            }};
            (this.authenticate(authParams)).join();
            return (this.watch(url, messageHash, this.extend(request, parameters), channel, extendedSubsription)).join();
        });

    }

    public java.util.concurrent.CompletableFuture<Object> authenticate(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object url = this.safeString(parameters, "url");
            Object hostname = this.safeString(parameters, "hostname");
            Object type = this.safeString(parameters, "type");
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(Helpers.isEqual(url, null)) || Helpers.isTrue(Helpers.isEqual(hostname, null))) || Helpers.isTrue(Helpers.isEqual(type, null))))
            {
                throw new ArgumentsRequired((String)Helpers.add(this.id, " authenticate requires a url, hostname and type argument")) ;
            }
            this.checkRequiredCredentials();
            Object messageHash = "auth";
            Object relativePath = Helpers.replace((String)url, (String)Helpers.add("wss://", hostname), (String)"");
            Client client = this.client(url);
            io.github.ccxt.ws.Future future = client.reusableFuture((String)messageHash);
            Object authenticated = this.safeValue(client.subscriptions, messageHash);
            if (Helpers.isTrue(Helpers.isEqual(authenticated, null)))
            {
                Object timestamp = this.ymdhms(this.milliseconds(), "T");
                Object signatureParams = null;
                if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                {
                    signatureParams = new java.util.HashMap<String, Object>() {{
                        put( "accessKey", HtxCore.this.apiKey );
                        put( "signatureMethod", "HmacSHA256" );
                        put( "signatureVersion", "2.1" );
                        put( "timestamp", timestamp );
                    }};
                } else
                {
                    signatureParams = new java.util.HashMap<String, Object>() {{
                        put( "AccessKeyId", HtxCore.this.apiKey );
                        put( "SignatureMethod", "HmacSHA256" );
                        put( "SignatureVersion", "2" );
                        put( "Timestamp", timestamp );
                    }};
                }
                signatureParams = this.keysort(signatureParams);
                Object auth = this.urlencode(signatureParams, true); // true required in go
                Object payload = String.join((String)"\n", (java.util.List<String>)(java.util.List)new java.util.ArrayList<Object>(java.util.Arrays.asList("GET", hostname, relativePath, auth))); // eslint-disable-line quotes
                Object signature = this.hmac(this.encode(payload), this.encode(this.secret), sha256(), "base64");
                Object request = null;
                if (Helpers.isTrue(Helpers.isEqual(type, "spot")))
                {
                    Object newParams = new java.util.HashMap<String, Object>() {{
                        put( "authType", "api" );
                        put( "accessKey", HtxCore.this.apiKey );
                        put( "signatureMethod", "HmacSHA256" );
                        put( "signatureVersion", "2.1" );
                        put( "timestamp", timestamp );
                        put( "signature", signature );
                    }};
                    request = new java.util.HashMap<String, Object>() {{
                        put( "params", newParams );
                        put( "action", "req" );
                        put( "ch", "auth" );
                    }};
                } else
                {
                    request = new java.util.HashMap<String, Object>() {{
                        put( "op", "auth" );
                        put( "type", "api" );
                        put( "AccessKeyId", HtxCore.this.apiKey );
                        put( "SignatureMethod", "HmacSHA256" );
                        put( "SignatureVersion", "2" );
                        put( "Timestamp", timestamp );
                        put( "Signature", signature );
                    }};
                }
                Object requestId = this.requestId();
                Object subscription = new java.util.HashMap<String, Object>() {{
                    put( "id", requestId );
                    put( "messageHash", messageHash );
                    put( "params", parameters );
                }};
                this.watch(url, messageHash, request, messageHash, subscription);
            }
            return ((io.github.ccxt.ws.Future)future).getFuture().join();
        });

    }
